css:
@import url('https://fonts.googleapis.com/css2?family=JetBrains+Mono:wght@400;500;600;700&family=DM+Sans:ital,wght@0,400;0,500;0,600;0,700;1,400&family=Playfair+Display:wght@700;800;900&display=swap');

:root {
  --co: #E87040;
  --co-l: #F4A261;
  --co-d: #C25A30;
  --bg0: #0F0F14;
  --bg1: #16161D;
  --bg2: #1C1C26;
  --bgt: #0A0A10;
  --tx: #E8E4DF;
  --tx2: #9B9690;
  --tx3: #6B6560;
  --grn: #6BCB77;
  --red: #E85D5D;
  --blu: #5B8DEF;
  --pur: #B07FD0;
  --brd: #2A2A35;
}

@page { size: A4; margin: 0; }

* { margin:0; padding:0; box-sizing:border-box; }

body {
  font-family: 'DM Sans', sans-serif;
  background: var(--bg0);
  color: var(--tx);
  line-height: 1.75;
  font-size: 15px;
  -webkit-font-smoothing: antialiased;
}

/* === COVER === */
.cover {
  min-height: 100vh;
  display: flex;
  flex-direction: column;
  justify-content: center;
  align-items: center;
  text-align: center;
  position: relative;
  overflow: hidden;
  padding: 60px 40px;
  background:
    radial-gradient(ellipse 80% 60% at 50% 0%, rgba(232,112,64,0.12) 0%, transparent 60%),
    radial-gradient(ellipse 60% 40% at 80% 80%, rgba(91,141,239,0.06) 0%, transparent 50%),
    var(--bg0);
  page-break-after: always;
}

.cover::before {
  content: '';
  position: absolute;
  inset: 0;
  background-image:
    repeating-linear-gradient(0deg, transparent, transparent 49px, rgba(232,112,64,0.03) 49px, rgba(232,112,64,0.03) 50px),
    repeating-linear-gradient(90deg, transparent, transparent 49px, rgba(232,112,64,0.03) 49px, rgba(232,112,64,0.03) 50px);
  pointer-events: none;
}

.cover-badge {
  display: inline-flex;
  align-items: center;
  gap: 8px;
  background: rgba(232,112,64,0.1);
  border: 1px solid rgba(232,112,64,0.25);
  border-radius: 100px;
  padding: 8px 20px;
  font-family: 'JetBrains Mono', monospace;
  font-size: 13px;
  color: var(--co);
  letter-spacing: 0.5px;
  margin-bottom: 40px;
  position: relative;
  z-index: 1;
}

.cover-badge::before { content: '> '; color: var(--grn); font-weight: 700; }

.cover h1 {
  font-family: 'Playfair Display', serif;
  font-size: clamp(44px, 7vw, 80px);
  font-weight: 900;
  line-height: 1.05;
  margin-bottom: 8px;
  position: relative;
  z-index: 1;
}

.hl {
  background: linear-gradient(135deg, var(--co), var(--co-l));
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
}

.cover h2 {
  font-family: 'Playfair Display', serif;
  font-size: clamp(24px, 4vw, 40px);
  font-weight: 700;
  color: var(--tx2);
  margin-bottom: 28px;
  position: relative;
  z-index: 1;
}

.cover p {
  font-size: 17px;
  color: var(--tx2);
  max-width: 520px;
  margin-bottom: 48px;
  position: relative;
  z-index: 1;
}

.cover-meta {
  display: flex;
  gap: 28px;
  flex-wrap: wrap;
  justify-content: center;
  font-family: 'JetBrains Mono', monospace;
  font-size: 12px;
  color: var(--tx3);
  position: relative;
  z-index: 1;
}

.cover-meta span::before { content: '◆ '; color: var(--co); font-size: 6px; vertical-align: middle; }

.prompt-line {
  position: absolute;
  bottom: 40px;
  font-family: 'JetBrains Mono', monospace;
  font-size: 14px;
  color: var(--tx3);
}

.cursor { display: inline-block; width: 8px; height: 17px; background: var(--co); animation: blink 1s step-end infinite; vertical-align: text-bottom; }
@keyframes blink { 0%,50%{opacity:1}51%,100%{opacity:0} }

/* === TOC === */
.toc {
  max-width: 760px;
  margin: 0 auto;
  padding: 80px 40px;
  page-break-after: always;
}

.section-label {
  font-family: 'JetBrains Mono', monospace;
  font-size: 12px;
  text-transform: uppercase;
  letter-spacing: 3px;
  color: var(--co);
  margin-bottom: 40px;
  display: block;
}

.toc-item {
  display: flex;
  align-items: baseline;
  gap: 16px;
  padding: 14px 0;
  border-bottom: 1px solid var(--brd);
}

.toc-n { font-family: 'JetBrains Mono', monospace; font-size: 13px; color: var(--co); min-width: 28px; }
.toc-t { font-size: 17px; font-weight: 600; flex: 1; }
.toc-s { font-size: 13px; color: var(--tx3); font-family: 'JetBrains Mono', monospace; }

/* === CHAPTER === */
.ch {
  max-width: 760px;
  margin: 0 auto;
  padding: 72px 40px;
  page-break-before: always;
}

.ch-head {
  margin-bottom: 40px;
  padding-bottom: 28px;
  border-bottom: 2px solid var(--brd);
  position: relative;
}

.ch-head::after { content:''; position:absolute; bottom:-2px; left:0; width:100px; height:2px; background:var(--co); }

.ch-num {
  font-family: 'JetBrains Mono', monospace;
  font-size: 12px;
  text-transform: uppercase;
  letter-spacing: 3px;
  color: var(--co);
  margin-bottom: 10px;
  display: block;
}

.ch-title {
  font-family: 'Playfair Display', serif;
  font-size: 32px;
  font-weight: 800;
  line-height: 1.15;
  margin-bottom: 10px;
}

.ch-obj { font-size: 16px; color: var(--tx2); font-style: italic; }

h3 {
  font-size: 20px;
  font-weight: 700;
  margin: 36px 0 14px;
  display: flex;
  align-items: center;
  gap: 10px;
}

.ico {
  width: 26px; height: 26px; border-radius: 6px;
  display: inline-flex; align-items: center; justify-content: center;
  font-size: 13px; flex-shrink: 0;
}

.ico-r { background: rgba(91,141,239,0.15); color: var(--blu); }
.ico-c { background: rgba(176,127,208,0.15); color: var(--pur); }
.ico-e { background: rgba(107,203,119,0.15); color: var(--grn); }
.ico-q { background: rgba(232,112,64,0.15); color: var(--co); }

p { margin-bottom: 14px; }

strong { color: var(--tx); font-weight: 600; }

/* === BLOCKS === */
.card {
  border: 1px solid var(--brd);
  border-radius: 10px;
  padding: 22px 24px;
  margin: 18px 0;
  background: var(--bg2);
}

.card.read { border-left: 3px solid var(--blu); }
.card.concept { border-left: 3px solid var(--pur); }

.card a {
  color: var(--blu);
  text-decoration: none;
  display: block;
  padding: 5px 0;
  font-size: 14px;
}

.card a::before { content: '→ '; color: var(--tx3); }
.card a:hover { color: var(--co-l); }

.card ul { list-style: none; }
.card li {
  padding: 7px 0 7px 18px;
  position: relative;
  font-size: 14px;
  border-bottom: 1px solid rgba(42,42,53,0.5);
}
.card li:last-child { border-bottom: none; }
.card li::before { content:'◆'; position:absolute; left:0; color:var(--pur); font-size:7px; top:13px; }

/* Exercise */
.ex {
  background: linear-gradient(135deg, rgba(107,203,119,0.05), rgba(107,203,119,0.02));
  border: 1px solid rgba(107,203,119,0.2);
  border-radius: 12px;
  padding: 24px;
  margin: 22px 0;
}

.ex-label {
  font-family: 'JetBrains Mono', monospace;
  font-size: 11px;
  text-transform: uppercase;
  letter-spacing: 2px;
  color: var(--grn);
  margin-bottom: 14px;
  display: flex;
  align-items: center;
  gap: 8px;
}

.ex-label::before { content: '▶'; }

.tag {
  display: inline-block;
  background: rgba(232,112,64,0.1);
  border: 1px solid rgba(232,112,64,0.2);
  color: var(--co);
  font-family: 'JetBrains Mono', monospace;
  font-size: 11px;
  padding: 3px 10px;
  border-radius: 4px;
  margin-bottom: 10px;
}

.ex ol, .ex ul { padding-left: 20px; font-size: 14px; }
.ex li { padding: 3px 0; }

/* Questions */
.qblock {
  background: var(--bg2);
  border: 1px solid rgba(232,112,64,0.2);
  border-radius: 12px;
  padding: 24px;
  margin: 24px 0;
  position: relative;
  overflow: hidden;
}

.qblock::before { content:''; position:absolute; top:0; left:0; right:0; height:3px; background:linear-gradient(90deg,var(--co),var(--co-l)); }

.qblock-h {
  font-family: 'JetBrains Mono', monospace;
  font-size: 11px;
  text-transform: uppercase;
  letter-spacing: 2px;
  color: var(--co);
  margin-bottom: 18px;
}

.qblock-h::before { content: '? '; font-weight: 700; font-size: 15px; }

.qi { padding: 14px 0; border-bottom: 1px solid var(--brd); }
.qi:last-child { border-bottom: none; }

.qi-n { font-family: 'JetBrains Mono', monospace; font-size: 12px; color: var(--co); margin-bottom: 4px; }
.qi-t { font-size: 14px; font-weight: 500; margin-bottom: 10px; }

.qi-a {
  min-height: 36px;
  border: 1px dashed var(--brd);
  border-radius: 6px;
  padding: 10px 14px;
  font-size: 12px;
  color: var(--tx3);
  font-family: 'JetBrains Mono', monospace;
  background: var(--bgt);
}

/* Terminal */
.term {
  background: var(--bgt);
  border: 1px solid var(--brd);
  border-radius: 10px;
  margin: 18px 0;
  overflow: hidden;
  font-family: 'JetBrains Mono', monospace;
  font-size: 13px;
  line-height: 1.7;
}

.term-bar {
  display: flex;
  align-items: center;
  gap: 7px;
  padding: 10px 16px;
  background: rgba(255,255,255,0.03);
  border-bottom: 1px solid var(--brd);
}

.term-dot { width:11px; height:11px; border-radius:50%; }
.term-dot.r { background:#FF5F57; }
.term-dot.y { background:#FFBD2E; }
.term-dot.g { background:#28C840; }
.term-f { margin-left: auto; font-size: 11px; color: var(--tx3); }

.term pre {
  padding: 16px 20px;
  overflow-x: auto;
  white-space: pre-wrap;
  word-break: break-all;
}

.c-g { color: var(--grn); }
.c-o { color: var(--co); }
.c-b { color: var(--blu); }
.c-p { color: var(--pur); }
.c-r { color: var(--red); }
.c-m { color: var(--tx3); }
.c-w { color: var(--tx); }

/* Diagram */
.diagram {
  background: var(--bg2);
  border: 1px solid var(--brd);
  border-radius: 12px;
  padding: 32px;
  margin: 24px 0;
  text-align: center;
  font-family: 'JetBrains Mono', monospace;
  font-size: 13px;
}

.diagram-flow {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 8px;
  flex-wrap: wrap;
  margin: 16px 0;
}

.diagram-box {
  padding: 10px 18px;
  border-radius: 8px;
  font-weight: 600;
  font-size: 12px;
  letter-spacing: 0.5px;
}

.diagram-arrow { color: var(--tx3); font-size: 18px; }

.db-orange { background: rgba(232,112,64,0.15); color: var(--co); border: 1px solid rgba(232,112,64,0.3); }
.db-blue { background: rgba(91,141,239,0.15); color: var(--blu); border: 1px solid rgba(91,141,239,0.3); }
.db-green { background: rgba(107,203,119,0.15); color: var(--grn); border: 1px solid rgba(107,203,119,0.3); }
.db-purple { background: rgba(176,127,208,0.15); color: var(--pur); border: 1px solid rgba(176,127,208,0.3); }

/* Info / Tip / Warning */
.tip {
  padding: 18px 22px;
  border-radius: 8px;
  margin: 18px 0;
  font-size: 14px;
  display: flex;
  gap: 12px;
  align-items: flex-start;
}

.tip-icon { font-size: 18px; flex-shrink: 0; margin-top: 2px; }
.tip.info { background: rgba(91,141,239,0.08); border: 1px solid rgba(91,141,239,0.2); }
.tip.warn { background: rgba(232,112,64,0.08); border: 1px solid rgba(232,112,64,0.2); }
.tip.ok { background: rgba(107,203,119,0.08); border: 1px solid rgba(107,203,119,0.2); }

/* Progress bar */
.progress {
  display: flex;
  gap: 4px;
  margin: 20px 0;
}

.progress-seg {
  height: 6px;
  flex: 1;
  border-radius: 3px;
  background: var(--brd);
}

.progress-seg.active { background: var(--co); }
.progress-seg.done { background: var(--grn); }

/* Checklist */
.check-item {
  display: flex;
  align-items: center;
  gap: 12px;
  padding: 10px 0;
  border-bottom: 1px solid var(--brd);
  font-size: 14px;
}

.check-box {
  width: 20px; height: 20px;
  border: 2px solid var(--brd);
  border-radius: 4px;
  flex-shrink: 0;
}

/* Footer */
.page-footer {
  text-align: center;
  padding: 40px;
  font-family: 'JetBrains Mono', monospace;
  font-size: 11px;
  color: var(--tx3);
  border-top: 1px solid var(--brd);
  margin-top: 40px;
}

/* Separator */
.sep {
  height: 1px;
  background: linear-gradient(90deg, transparent, var(--brd), transparent);
  margin: 32px 0;
}

/* File tree */
.filetree {
  background: var(--bgt);
  border: 1px solid var(--brd);
  border-radius: 8px;
  padding: 18px 22px;
  font-family: 'JetBrains Mono', monospace;
  font-size: 13px;
  line-height: 1.8;
  margin: 16px 0;
}

.filetree .dir { color: var(--blu); }
.filetree .file { color: var(--tx2); }
.filetree .hl-file { color: var(--co); font-weight: 600; }

/* Inline code */
code {
  font-family: 'JetBrains Mono', monospace;
  font-size: 0.88em;
  background: rgba(232,112,64,0.08);
  color: var(--co-l);
  padding: 2px 7px;
  border-radius: 4px;
}

/* Table */
table {
  width: 100%;
  border-collapse: collapse;
  margin: 18px 0;
  font-size: 13px;
}

th {
  text-align: left;
  padding: 10px 14px;
  background: var(--bg2);
  border-bottom: 2px solid var(--co);
  font-family: 'JetBrains Mono', monospace;
  font-size: 11px;
  text-transform: uppercase;
  letter-spacing: 1px;
  color: var(--co);
}

td {
  padding: 10px 14px;
  border-bottom: 1px solid var(--brd);
  color: var(--tx2);
}

tr:hover td { background: rgba(232,112,64,0.03); }
